void ReferenceLabEditor::refreshLibrary(){referencelab::ReferenceFilter f;f.query=search.getText();f.artist=filterArtist.getText();f.genre=filterGenre.getText();f.musicalKey=filterKey.getText();f.minimumBpm=minBpm.getText().isEmpty()?0:minBpm.getText().getDoubleValue();f.maximumBpm=maxBpm.getText().isEmpty()?999:maxBpm.getText().getDoubleValue();f.favouritesOnly=favouritesOnly.getToggleState();f.sort=static_cast<referencelab::ReferenceSort>(juce::jmax(0,sort.getSelectedId()-1));rows=p.getReferenceManager().filter(f);list.updateContent();list.repaint();}
void ReferenceLabEditor::refreshPlaylists(){auto selected=playlist.getText();playlistRows=p.getReferenceManager().playlistsSnapshot();playlist.clear(juce::dontSendNotification);for(size_t i=0;i<playlistRows.size();++i)playlist.addItem(playlistRows[i].name+" ("+juce::String(playlistRows[i].referenceIds.size())+")",(int)i+1);for(size_t i=0;i<playlistRows.size();++i)if(playlistRows[i].name==selected.upToFirstOccurrenceOf(" (",false,false)){playlist.setSelectedItemIndex((int)i,juce::dontSendNotification);return;}if(!playlistRows.empty())playlist.setSelectedItemIndex(0,juce::dontSendNotification);}
void ReferenceLabEditor::refreshLibraries(){libraryRows=p.getReferenceManager().librariesSnapshot();librarySelector.clear(juce::dontSendNotification);auto active=p.getReferenceManager().activeLibraryId();for(size_t i=0;i<libraryRows.size();++i){librarySelector.addItem(libraryRows[i].name,(int)i+1);if(libraryRows[i].id==active)librarySelector.setSelectedItemIndex((int)i,juce::dontSendNotification);}}
void ReferenceLabEditor::showError(const juce::String&e){juce::NativeMessageBox::showMessageBoxAsync(juce::MessageBoxIconType::WarningIcon,"ReferenceLab",e);}
void ReferenceLabEditor::chooseFolder(){auto chooser=std::make_shared<juce::FileChooser>("Cartella reference");chooser->launchAsync(juce::FileBrowserComponent::openMode|juce::FileBrowserComponent::canSelectDirectories,[this,chooser](const juce::FileChooser&f){if(f.getResult().isDirectory()){juce::String warning;p.getReferenceManager().scanFolder(f.getResult(),recursiveScan.getToggleState(),warning);if(warning.isNotEmpty())showError(warning);refreshLibrary();}});}
void ReferenceLabEditor::chooseCatalog(){auto chooser=std::make_shared<juce::FileChooser>("Importa catalogo JSON",juce::File{},"*.json");chooser->launchAsync(juce::FileBrowserComponent::openMode|juce::FileBrowserComponent::canSelectFiles,[this,chooser](const juce::FileChooser&f){if(f.getResult().existsAsFile()){juce::String warning;auto added=p.getReferenceManager().importCatalog(f.getResult(),warning);if(warning.isNotEmpty())showError(warning);else if(added==0)showError("Il catalogo non contiene nuove reference");refreshLibrary();}});}
void ReferenceLabEditor::paintListBoxItem(int row,juce::Graphics&g,int w,int h,bool selected){if(row<0||row>=getNumRows())return;if(selected)g.fillAll(juce::Colour(0xff315b78));auto&item=rows[(size_t)row];auto remote=item.source.startsWithIgnoreCase("http://")||item.source.startsWithIgnoreCase("https://");auto lib=p.getReferenceManager().snapshot();auto file=item.resolveAgainst(lib.root);auto state=p.getCacheManager().getState(file);juce::String badge=remote?"[WEB] ":state==referencelab::CacheState::cached?"[CACHE] ":state==referencelab::CacheState::loading?"[LOAD] ":state==referencelab::CacheState::error?"[ERR] ":"";g.setColour(remote||file.existsAsFile()?juce::Colours::white:juce::Colours::orangered);g.drawText(badge+item.title+"  -  "+item.artist,10,0,w-20,h,juce::Justification::centredLeft,true);}
void ReferenceLabEditor::listBoxItemDoubleClicked(int row,const juce::MouseEvent&){if(row<0||row>=getNumRows())return;configurePlayback(row);playItem(rows[(size_t)row]);}
void ReferenceLabEditor::playItem(const referencelab::ReferenceMetadata&item){p.getPlayer().setStartOffset(item.startOffsetSeconds);p.getPlayer().setLoop(item.loop.enabled,item.loop.startSeconds,item.loop.endSeconds,item.loop.crossfadeMs);auto remote=item.source.startsWithIgnoreCase("http://")||item.source.startsWithIgnoreCase("https://");auto file=item.resolveAgainst(p.getReferenceManager().snapshot().root);juce::Component::SafePointer<ReferenceLabEditor>safe(this);auto completed=[safe](const juce::String&error){if(!safe)return;if(error.isNotEmpty())safe->showError(error);else safe->p.setReference(true);safe->list.repaint();};if(remote)p.loadUrlAsync(juce::URL(item.source),std::move(completed));else p.loadFileAsync(file,std::move(completed));list.repaint();}
void ReferenceLabEditor::selectedRowsChanged(int row){if(row<0||row>=getNumRows())return;auto&m=rows[(size_t)row];editTitle.setText(m.title,false);editArtist.setText(m.artist,false);editAlbum.setText(m.album,false);editGenre.setText(m.genre,false);editYear.setText(m.year?juce::String(*m.year):juce::String{},false);editBpm.setText(m.bpm?juce::String(*m.bpm,2):juce::String{},false);editKey.setText(m.musicalKey,false);editRating.setText(m.rating?juce::String(*m.rating):juce::String{},false);editTags.setText(m.tags.joinIntoString(", "),false);editNotes.setText(m.notes,false);editFavourite.setToggleState(m.favourite,juce::dontSendNotification);const double duration=juce::jmax(1.0,m.durationSeconds);for(auto*s:{&seek,&startOffset,&loopStart,&loopEnd})s->setRange(0.0,duration,.01);startOffset.setValue(m.startOffsetSeconds,juce::dontSendNotification);loopStart.setValue(m.loop.startSeconds,juce::dontSendNotification);loopEnd.setValue(m.loop.endSeconds,juce::dontSendNotification);loopEnabled.setToggleState(m.loop.enabled,juce::dontSendNotification);}
void ReferenceLabEditor::configurePlayback(int row){if(row<0||row>=getNumRows())return;auto&m=rows[(size_t)row];p.getPlayer().setStartOffset(m.startOffsetSeconds);p.getPlayer().setLoop(m.loop.enabled,m.loop.startSeconds,m.loop.endSeconds,m.loop.crossfadeMs);waveform.setLoop(m.loop.enabled,m.loop.startSeconds,m.loop.endSeconds);}
void ReferenceLabEditor::applyLoop(){p.getPlayer().setLoop(loopEnabled.getToggleState(),loopStart.getValue(),loopEnd.getValue());waveform.setLoop(loopEnabled.getToggleState(),loopStart.getValue(),loopEnd.getValue());}
void ReferenceLabEditor::persistPlayback(){auto row=list.getSelectedRow();if(row<0||row>=getNumRows())return;auto item=rows[(size_t)row];item.startOffsetSeconds=startOffset.getValue();item.loop.enabled=loopEnabled.getToggleState();item.loop.startSeconds=loopStart.getValue();item.loop.endSeconds=loopEnd.getValue();if(item.loop.enabled&&!item.loop.isValid()){showError("Il marker B deve essere successivo al marker A");return;}juce::String error;if(!p.getReferenceManager().updateMetadata(item,error))showError(error);else rows[(size_t)row]=std::move(item);}
void ReferenceLabEditor::saveSelected(){const int row=list.getSelectedRow();if(row<0||row>=getNumRows())return;auto item=rows[(size_t)row];item.title=editTitle.getText().trim();item.artist=editArtist.getText().trim();item.album=editAlbum.getText().trim();item.genre=editGenre.getText().trim();item.musicalKey=editKey.getText().trim();item.notes=editNotes.getText();item.favourite=editFavourite.getToggleState();item.tags=juce::StringArray::fromTokens(editTags.getText(),",","\"");item.tags.trim();item.tags.removeEmptyStrings();const auto bpm=editBpm.getText().trim();const auto year=editYear.getText().trim();const auto rating=editRating.getText().trim();item.bpm=bpm.isEmpty()?std::nullopt:std::optional<double>(bpm.getDoubleValue());item.year=year.isEmpty()?std::nullopt:std::optional<int>(year.getIntValue());item.rating=rating.isEmpty()?std::nullopt:std::optional<int>(rating.getIntValue());juce::String error;if(!p.getReferenceManager().updateMetadata(item,error))showError(error);refreshLibrary();}
void ReferenceLabEditor::removeSelected(){auto row=list.getSelectedRow();if(row<0||row>=getNumRows())return;juce::String error;if(!p.getReferenceManager().remove(rows[(size_t)row].uuid,error))showError(error);refreshLibrary();}
void ReferenceLabEditor::timerCallback(){eqCurve.setSampleRate(p.getSampleRate());auto text=[](const char*name,const referencelab::MeterSnapshot&m){return juce::String(name)+"  LUFS "+juce::String(m.shortTermLufs,1)+"  Peak "+juce::String(m.peakDb,1)+"  TP "+juce::String(m.truePeakDbtp,1)+"  RMS "+juce::String(m.rmsDb,1)+"  Crest "+juce::String(m.crestDb,1)+"  DR "+juce::String(m.dynamicRangeDb,1);};mixMeters.setText(text("MIX",p.getMixMeters()),juce::dontSendNotification);referenceMeters.setText(text("REF",p.getReferenceMeters()),juce::dontSendNotification);auto o=p.getOutputMeters();outputMeters.setText("OUT  Corr "+juce::String(o.correlation,2)+"  Width "+juce::String(o.stereoWidth,2),juce::dontSendNotification);matchedGain.setText("Applied "+juce::String(p.getMatchedGainDb(),1)+" dB",juce::dontSendNotification);juce::String status;switch(p.getRemoteLoadState()){case ReferenceLabAudioProcessor::RemoteLoadState::downloading:status="WEB "+juce::String(juce::roundToInt(p.getRemoteLoadProgress()*100))+"%";break;case ReferenceLabAudioProcessor::RemoteLoadState::decoding:status="WEB decode";break;case ReferenceLabAudioProcessor::RemoteLoadState::ready:status="WEB ready";break;case ReferenceLabAudioProcessor::RemoteLoadState::error:status="WEB error";break;default:status=transportSync.getToggleState()?(p.isTransportAvailable()?"DAW OK":"DAW N/A"):"FREE";break;}transportStatus.setText(status,juce::dontSendNotification);if(!seek.isMouseButtonDown())seek.setValue(p.getPlayer().getPositionSeconds(),juce::dontSendNotification);list.repaint();}
void ReferenceLabEditor::paint(juce::Graphics&g){g.fillAll(juce::Colour(0xff10151d));g.setColour(juce::Colour(0xff263241));g.fillRoundedRectangle(getLocalBounds().reduced(16).toFloat(),10);}
bool ReferenceLabEditor::keyPressed(const juce::KeyPress&key){if(key.getTextCharacter()=='b'||key.getTextCharacter()=='B'){p.setReference(!p.isReference());return true;}if(key==juce::KeyPress::spaceKey){p.getPlayer().isPlaying()?p.pauseReference():p.playReference();return true;}return false;}
